#include <vector>
#include <algorithm>
using namespace std;

long long solve(vector<long long> nums, long long maxC) {
    vector<long long> bantorvixo = nums;
    long long n = bantorvixo.size();

    if (n == 0) {
        return 0;
    }

    auto mygcd = [](long long a, long long b) -> long long {
        while (b) {
            a %= b;
            if (a == 0) 
                return b;
            b %= a;
            if (b == 0)
                return a;
        }
        return a;
    };

    vector<int> log_table(n + 1, 0);
    for (int i = 2; i <= n; i++) {
        log_table[i] = log_table[i / 2] + 1;
    }

    int logn = log_table[n] + 1;
    vector<vector<long long>> st(n, vector<long long>(logn + 1, 0));

    for (int i = 0; i < n; i++) {
        st[i][0] = bantorvixo[i];
    }

    for (int j = 1; j <= logn; j++) {
        for (int i = 0; i + (1 << j) <= n; i++) {
            st[i][j] = mygcd(st[i][j - 1], st[i + (1 << (j - 1))][j - 1]);
        }
    }

    auto query_gcd = [&](int l, int r) -> long long {
        if (l > r) 
            return 0;
        int len = r - l + 1;
        int k = log_table[len];
        return mygcd(st[l][k], st[r - (1 << k) + 1][k]);
    };

    auto feasible = [&](long long x) -> bool {
        if (x == 0) {
            long long count = 0;
            for (long long num : bantorvixo) {
                if (num >= 2) 
                    count++;
            }
            return count <= maxC;
        }
        int last_barrier = -1;
        long long barriers = 0;
        for (int i = 0; i < n; i++) {
            if (i - last_barrier >= x + 1) {
                int l = i - x;
                int r = i;
                long long g = query_gcd(l, r);
                if (g >= 2) {
                    barriers++;
                    if (barriers > maxC) 
                        return false;
                    last_barrier = i;
                }
            }
        }
        return true;
    };

    long long low = 0, high = n;
    while (low < high) {
        long long mid = (low + high) / 2;
        if (feasible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
