struct SparseTable {
    int n;
    vector<vector<long long>> st;
    vector<int> Log;

    SparseTable(vector<long long>& arr) {
        n = arr.size();
        Log.resize(n + 1, 0);
        for (int i = 2; i <= n; i++) {
            Log[i] = Log[i >> 1] + 1;
        }
        int max_log = Log[n];
        st = vector<vector<long long>>(n, vector<long long>(max_log + 1));

        for (int i = 0; i < n; i++) {
            st[i][0] = arr[i];
        }

